// Milestone 1: translate_address()
trans_output_t translate_address(
simulator_t *sim,
uint32_t va,
bool is_write
) {
// 1. ALWAYS increment total_accesses
sim->stats.total_accesses++;
uint32_t vpn = va >> PAGE_SHIFT;
pte_t *pte = &sim->page_table[vpn];
// 2. Check valid bit
if (!pte->valid) {
sim->stats.page_faults++;  // ← HERE
// ... handle fault ...
}
// 3. Check permissions
if (is_write && !pte->writable) {
sim->stats.protection_faults++;  // ← HERE
return TRANS_PROTECTION_FAULT;
}
// ...
}
